import { PropostaService } from './proposta.service';
import { HttpClient } from '@angular/common/http';
import { of } from 'rxjs';

describe('PropostaService', () => {
  let service: PropostaService;
  let httpMock: jest.Mocked<HttpClient>;

  beforeEach(() => {
    httpMock = {
      post: jest.fn(),
      get: jest.fn(),
      put: jest.fn(),
    } as any;
    service = new PropostaService(httpMock as any);
  });

  it('deve criar proposta via POST', () => {
    const mockResponse = { id: '1', cpfCnpj: '52998224725' };
    httpMock.post.mockReturnValue(of(mockResponse));

    service.criar('52998224725').subscribe(res => {
      expect(res).toEqual(mockResponse);
    });

    expect(httpMock.post).toHaveBeenCalledWith(
      '/api/propostas',
      { cpfCnpj: '52998224725' },
      expect.any(Object) as any
    );
  });

  it('deve buscar proposta por id via GET', () => {
    httpMock.get.mockReturnValue(of({ id: '1' }));

    service.buscar('1').subscribe(res => {
      expect(res.id).toBe('1');
    });

    expect(httpMock.get).toHaveBeenCalledWith('/api/propostas/1');
  });

  it('deve atualizar dados pessoais via PUT', () => {
    httpMock.put.mockReturnValue(of({ id: '1', nomeCompleto: 'Joao' }));

    const dados = { nomeCompleto: 'Joao' };
    service.atualizarDadosPessoais('1', dados as any).subscribe();

    expect(httpMock.put).toHaveBeenCalledWith(
      '/api/propostas/1/dados-pessoais',
      dados,
      expect.any(Object) as any
    );
  });

  it('deve listar todas as propostas via GET', () => {
    httpMock.get.mockReturnValue(of([]));
    service.listar().subscribe(res => expect(res).toEqual([]));
    expect(httpMock.get).toHaveBeenCalledWith('/api/propostas');
  });

  it('deve chamar criar conta via POST', () => {
    httpMock.post.mockReturnValue(of({ id: 'c1', agencia: '1234' }));
    service.criarConta('1', 'CORRENTE').subscribe();
    expect(httpMock.post).toHaveBeenCalledWith(
      '/api/propostas/1/conta/criar',
      { tipoConta: 'CORRENTE' }
    );
  });
});
